public async Task<bool> PurchaseTickets(int eventId, int purchaseQuantity)
{
    using (var context = new EventBookingContext())
    {
        var eventInfo = await context.Events.FindAsync(eventId);

        if (eventInfo == null)
        {
            return false;
        }

        // Check available seats
        if (eventInfo.AvailableSeats < purchaseQuantity)
        {
            return false;
        }

        // Validate purchase quantity
        if (purchaseQuantity <= 0)
